export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(keyOf));
  const survivors = cells.filter((cell) => {
    const liveNeighbors = countLiveNeighbors(cell, aliveKeys);
    return liveNeighbors === 2 || liveNeighbors === 3;
  });
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = `${nx},${ny}`;
      if (!aliveKeys.has(k)) candidates.set(k, [nx, ny]);
    }
  }
  const births: Cell[] = [];
  for (const cell of candidates.values()) {
    if (countLiveNeighbors(cell, aliveKeys) === 3) births.push(cell);
  }
  return [...survivors, ...births];
}

